    [ApiController]
    [Route("[controller]")]
    public class ProxyController : ControllerBase
    {
        private readonly IConfiguration _configuration;
        private readonly IDictionary<string, string> _secrets = new Dictionary<string, string>();

        public ProxyController(IConfiguration configuration)
        {
            _configuration = configuration;

            foreach (var secret in _configuration.AsEnumerable())
            {
                if (!string.IsNullOrEmpty(secret.Value))
                    _secrets[secret.Key] = secret.Value;
            }
