        [HttpPost("{url}")]
        public async Task<IActionResult> ForwardRequest([FromRoute] string url, [FromBody] byte[] body)
        {
            if (!_secrets.TryGetValue(url, out var secret))
                return BadRequest($"No HMAC secret provided for URL: {url}");

            var hmac = new HMACSHA256(Encoding.UTF8.GetBytes(secret));
            var computedHash = hmac.ComputeHash(body);

            var requestHeaders = Request.Headers;
            var headerValue = requestHeaders["X-HMAC"];

            if (headerValue == null || !VerifyHashes(computedHash, headerValue))
                return Unauthorized();

            using var client = new HttpClient();
            var response = await client.PostAsync($"{url}", new ByteArrayContent(body));
            response.EnsureSuccessStatusCode();

            return Ok(await response.Content.ReadAsStreamAsync());
        }

        private bool VerifyHashes(byte[] computedHash, string headerValue)
        {
            var receivedBytes = Convert.FromBase64String(headerValue);
            var receivedHmac = new HMACSHA256(Encoding.UTF8.GetBytes(_secrets[url]));
            return receivedHmac.ComputeHash(receivedBytes)
                .SequenceEqual(computedHash);
